class Solution:
    def missingNumber(self, nums):
        present = set(nums)
        for i in range(len(nums) + 1):
            if i not in present:
                return i

solutions.python:
class Solution:
    def missingNumber(self, nums):
        n = len(nums)
        return n * (n + 1) // 2 - sum(nums)

solutions.javascript:
var missingNumber = function(nums) {
    const n = nums.length;
    let total = n * (n + 1) / 2;
    for (const x of nums) total -= x;
    return total;
};
